#!/bin/bash
# Pattern : Command Pattern (commandes enregistrables et annulables)

declare -a COMMAND_HISTORY
declare -a UNDO_STACK

register_command() {
    local name=$1 do_cmd=$2 undo_cmd=$3
    COMMAND_HISTORY+=("$name")
    execute_command() { eval "$do_cmd"; }
    UNDO_STACK+=("$undo_cmd")
}

undo_last() {
    if [ ${#UNDO_STACK[@]} -eq 0 ]; then
        echo "Rien à annuler"
        return 1
    fi
    local last_undo=${UNDO_STACK[-1]}
    unset 'UNDO_STACK[-1]'
    eval "$last_undo"
    echo "Annulé"
}

# Pattern : Observer
declare -A OBSERVERS

subscribe() {
    local event=$1 callback=$2
    OBSERVERS["$event"]+="$callback "
}

emit() {
    local event=$1; shift
    for cb in ${OBSERVERS[$event]:-}; do
        "$cb" "$@"
    done
}

# Utilisation
on_file_created() { echo "Observateur: fichier créé - $1"; }
subscribe "file_created" on_file_created

touch /tmp/test_file
emit "file_created" /tmp/test_file
rm /tmp/test_file
